    32→export class AuthClientError extends Error {
    33→  code: AuthClientErrorCode;
    34→  retryable: boolean;
    35→
    36→  constructor(
    37→    code: AuthClientErrorCode,
    38→    message: string,
    39→    options: { retryable?: boolean; cause?: unknown } = {}
