   122→    case "AccessDenied":
   123→      return new AuthClientError("access_denied", "Access denied for this account.");
   124→    default:
   125→      if (errorCode === "credentials") {
   126→        return new AuthClientError("invalid_credentials", "Invalid phone/email or password.", { retryable: true });
   127→      }
   128→      return new AuthClientError("unknown_error", DEFAULT_SIGN_IN_ERROR, { retryable: true });
