   200→export async function signInWithCredentials(
   201→  identifier: string,
   202→  password: string,
   203→  options: SignInWithCredentialsOptions = {}
   204→): Promise<void> {
   205→  const maxAttempts = normalizeAttempts(options.maxAttempts);
   206→  const retryDelayMs = normalizeDelayMs(options.retryDelayMs);
   207→
   208→  for (let attempt = 1; attempt <= maxAttempts; attempt += 1) {
   209→    try {
   210→      await signInWithCredentialsOnce(identifier, password);
   211→      return;
   212→    } catch (error) {
   213→      const authError = toAuthClientError(error, DEFAULT_SIGN_IN_ERROR);
   214→      const shouldRetry = authError.retryable && attempt < maxAttempts;
   215→      if (!shouldRetry) throw authError;
   216→      await delay(retryDelayMs);
   217→    }
   218→  }
   219→}
