   258→    failed,
   259→    syncedIds,
   260→    failedIds,
   261→    permanentFailures,
   262→    permanentFailureIds,
   263→    permanentFailureMessages: Array.from(permanentFailureMessages),
   264→    remaining,
   265→  };
   266→}
